const header = $('Header').item.json.output;
const description = $json.output;
const venueData = $('Get Venue ID').first().json;

return [{
  json: {
    body: {
      modules: [
        {
          type: 'text',
          data: {
            body: {
              type: 'text',
              text: `<p><strong>${header}</strong></p>`,
              alignment: 'left'
            }
          }
        },
        {
          type: 'text',
          data: {
            body: {
              type: 'text',
              text: `<p>${description}</p>`,
              alignment: 'left'
            }
          }
        },
        {
          type: 'text',
          data: {
            body: {
              type: 'text',
              text: "<p><strong>What to expect:</strong></p><ul><li>Curated peer-level conversations</li><li>Exposure to complementary industries</li><li>Potential partnership opportunities</li><li>Clear next steps for follow-up</li></ul>",
              alignment: 'left'
            }
          }
        }
      ],
      widgets: [
        {
          type: 'agenda',
          data: {
            tabs: [
              {
                slots: venueData.slots,
                name: 'Agenda'
              }
            ]
          }
        },
        {
          type: 'parking',
          data: {
            availability: 'paid'
          }
        },
        {
          type: 'faqs',
          data: {
            faqs: venueData.faqs
          }
        }
      ],
      publish: true,
      purpose: 'listing'
    }
  }
}];

