// Access n8n's global memory for this workflow
const staticData = $getWorkflowStaticData('global');

// Get the unique API URL for this specific event from the webhook body
const apiUrl = $input.item.json.body.api_url; 
const now = Date.now();

// Initialize memory if this is the very first time the workflow is running
if (!staticData.lastTriggers) {
  staticData.lastTriggers = {};
}

const lastTriggerTime = staticData.lastTriggers[apiUrl];

// Check if this EXACT event was triggered less than 15 seconds ago (15000 ms)
if (lastTriggerTime && (now - lastTriggerTime < 15000)) {
  // It's the 1-second duplicate! Returning an empty array stops the workflow here.
  return [];
}

// It's a valid, new update! Save the current time for this event...
staticData.lastTriggers[apiUrl] = now;

// ...and pass the data forward so the rest of your workflow can run.
return $input.item;

